"use client";

import React from "react";
import * as Scrollytelling from "@bsmnt/scrollytelling";
import { ScrollTrigger } from "gsap/ScrollTrigger";

export interface PinnedCrossfadeProps {
  /** the panel shown first — pinned, then dissolves away */
  first: React.ReactNode;
  /** the panel that resolves in over the first */
  second: React.ReactNode;
  /** how long the section stays pinned, in viewport heights (clamped 1.5-3) */
  hold?: number;
  className?: string;
}

const prefers = (q: string): boolean =>
  typeof window !== "undefined" &&
  typeof window.matchMedia === "function" &&
  window.matchMedia(q).matches;

/*
 * Two-panel pinned crossfade: the section pins for a controlled distance while panel one dissolves
 * into panel two, tied to scroll position rather than to time.
 *
 * SAFETY IS BAKED IN, not left to the caller:
 *  - prefers-reduced-motion OR a coarse pointer (touch) renders the two panels as a plain vertical
 *    stack with no pin and no fade. Both panels stay fully readable, which is the required fallback
 *    anyway -- "never pin on touch" is a hard rule, not a preference.
 *  - the pin distance is clamped to 1.5-3 viewport heights, so the page can never trap the reader.
 *  - the crossfade window is fixed at 30-70% of the pinned timeline: each panel is fully opaque at
 *    its own end of the scroll, so neither is ever stuck half-legible.
 *  - only opacity animates (never layout), and each panel stands alone if motion never runs.
 *  - STALE-POSITION GUARD: an image that finishes loading late (generated imagery renders on demand)
 *    shifts the layout ABOVE this section after ScrollTrigger measured its start/end -- the observed
 *    failure is both panels stuck at full opacity. Any document image still pending at mount gets a
 *    settle listener that schedules ONE trailing ScrollTrigger.refresh(), so positions re-measure
 *    after the page reaches its real height. refresh() is idempotent; multiple instances coexist.
 *
 * Deliberately NOT video-backed. A pinned <video> is the documented low-end-hardware failure mode
 * (see the PP Neue Montreal critique) -- this variant carries the same narrative beat with two
 * ordinary content panels.
 */
export function PinnedCrossfade({ first, second, hold = 2, className }: PinnedCrossfadeProps) {
  const staticFallback = prefers("(prefers-reduced-motion: reduce)") || prefers("(pointer: coarse)");

  React.useEffect(() => {
    if (staticFallback) return;
    const pending = Array.from(document.querySelectorAll("img")).filter((i) => !i.complete);
    if (!pending.length) return;
    let timer: ReturnType<typeof setTimeout> | undefined;
    const settle = () => {
      if (timer) clearTimeout(timer);
      timer = setTimeout(() => ScrollTrigger.refresh(), 150);
    };
    for (const img of pending) {
      img.addEventListener("load", settle, { once: true });
      img.addEventListener("error", settle, { once: true });
    }
    return () => {
      if (timer) clearTimeout(timer);
      for (const img of pending) {
        img.removeEventListener("load", settle);
        img.removeEventListener("error", settle);
      }
    };
  }, [staticFallback]);

  if (staticFallback) {
    return (
      <section className={className}>
        <div>{first}</div>
        <div>{second}</div>
      </section>
    );
  }

  // Clamp the pin distance. A bad prop degrades to a sane hold rather than a scroll trap.
  const held = Math.min(3, Math.max(1.5, Number(hold) || 2));

  return (
    <section className={className}>
      <Scrollytelling.Root start="top top" end="bottom bottom" scrub={0.8}>
        <Scrollytelling.Pin childHeight="100vh" pinSpacerHeight={String(held * 100) + "vh"}>
          <div style={{ position: "relative", height: "100vh", overflow: "hidden" }}>
            {/* ease:"none" is mandatory here, not taste: the scroll position IS the clock, and gsap's
                default power1.out would ease on top of the scrub -- measured 25/75 at the scroll
                midpoint instead of 50/50, so panel two reads as arriving early. Linear keeps the
                dissolve locked to the reader's own scrolling. */}
            <Scrollytelling.Animation tween={{ start: 30, end: 70, fromTo: [{ opacity: 1 }, { opacity: 0, ease: "none" }] }}>
              <div style={{ position: "absolute", inset: 0 }}>{first}</div>
            </Scrollytelling.Animation>
            <Scrollytelling.Animation tween={{ start: 30, end: 70, fromTo: [{ opacity: 0 }, { opacity: 1, ease: "none" }] }}>
              <div style={{ position: "absolute", inset: 0 }}>{second}</div>
            </Scrollytelling.Animation>
          </div>
        </Scrollytelling.Pin>
      </Scrollytelling.Root>
    </section>
  );
}

export default PinnedCrossfade;

