import { PinnedCrossfade } from "./component"

// TWO full-viewport panels; the first dissolves into the second while the section is pinned.
// Pass real, on-brief content for each panel -- each must stand alone if motion never runs.
export default function Section() {
  return (
    <PinnedCrossfade
      hold={2}
      className="bg-background"
      first={
        <div className="h-full flex items-center justify-center px-6">
          <h2 className="text-foreground text-5xl md:text-7xl font-bold tracking-tight max-w-3xl text-center">
            The first on-brief statement
          </h2>
        </div>
      }
      second={
        <div className="h-full flex items-center justify-center px-6 bg-card">
          <p className="text-card-foreground text-2xl md:text-3xl max-w-2xl text-center">
            The second beat it resolves into, in the brand voice.
          </p>
        </div>
      }
    />
  )
}
